import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  Chip,
  IconButton,
  Tooltip,
  CircularProgress,
  useTheme,
  Button,
  TextField,
  MenuItem,
  Grid,
  Alert
} from '@mui/material';
import {
  Close,
  TrendingUp,
  TrendingDown,
  Refresh,
  FilterList,
  Download
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const FinishedOperationsModal = ({ open, onClose, hideValues = false }) => {
  const theme = useTheme();
  const [positions, setPositions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [refreshing, setRefreshing] = useState(false);

  useEffect(() => {
    if (open) {
      loadFinishedPositions();
    }
  }, [open]);

  const loadFinishedPositions = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await dashboardService.getFinishedPositions();
      setPositions(data.positions || data || []);
    } catch (err) {
      console.error('Erro ao carregar posições:', err);
      setError(err.message || 'Erro ao carregar posições');
    } finally {
      setLoading(false);
    }
  };

  const handleRefresh = async () => {
    setRefreshing(true);
    await loadFinishedPositions();
    setRefreshing(false);
  };

  const formatCurrency = (value, currency = 'USDT') => {
    if (hideValues) return `*** ${currency}`;
    const numValue = parseFloat(value || 0);

    if (Math.abs(numValue) < 0.001 && numValue !== 0) {
      return `${numValue.toFixed(8)} ${currency}`;
    }

    if (Math.abs(numValue) < 0.1 && numValue !== 0) {
      return `${numValue.toFixed(6)} ${currency}`;
    }

    if (Math.abs(numValue) < 1) {
      return `${numValue.toFixed(4)} ${currency}`;
    }

    return `${numValue.toFixed(2)} ${currency}`;
  };

  const formatPercentage = (value) => {
    if (hideValues) return '***%';
    if (value === null || value === undefined) return '0%';

    if (Math.abs(value) < 0.01 && value !== 0) {
      return `${value >= 0 ? '+' : ''}${parseFloat(value).toFixed(6)}%`;
    }

    if (Math.abs(value) < 1) {
      return `${value >= 0 ? '+' : ''}${parseFloat(value).toFixed(4)}%`;
    }

    return `${value >= 0 ? '+' : ''}${parseFloat(value).toFixed(2)}%`;
  };

  const formatDate = (timestamp) => {
    if (!timestamp) return '-';
    return new Date(parseInt(timestamp)).toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getColorByValue = (value) => {
    if (value > 0) return '#02c076'; // Verde
    if (value < 0) return '#f84960'; // Vermelho
    return '#848e9c'; // Cinza neutro
  };

  const getSideColor = (side) => {
    return side === 'long' ? '#02c076' : '#f84960';
  };

  const getMarginModeText = (mode) => {
    return mode === 'isolated' ? 'Isolado' : 'Cruzado';
  };

  const getPosModeText = (mode) => {
    return mode === 'hedge_mode' ? 'Hedge' : 'One-Way';
  };

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="xl"
      fullWidth
      PaperProps={{
        sx: {
          backgroundColor: '#1C2127',
          color: 'white',
          minHeight: '80vh'
        }
      }}
    >
      <DialogTitle sx={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        borderBottom: '1px solid #2D3748',
        pb: 2
      }}>
        <Typography variant="h6" component="div">
          Operações Finalizadas - Bitget API
        </Typography>
        <Box sx={{ display: 'flex', gap: 1 }}>
          <Tooltip title="Atualizar">
            <IconButton 
              onClick={handleRefresh}
              disabled={refreshing}
              sx={{ color: 'white' }}
            >
              {refreshing ? <CircularProgress size={20} /> : <Refresh />}
            </IconButton>
          </Tooltip>
          <Tooltip title="Fechar">
            <IconButton onClick={onClose} sx={{ color: 'white' }}>
              <Close />
            </IconButton>
          </Tooltip>
        </Box>
      </DialogTitle>

      <DialogContent sx={{ p: 0 }}>
        {error && (
          <Alert severity="error" sx={{ m: 2 }}>
            {error}
          </Alert>
        )}

        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', p: 4 }}>
            <CircularProgress />
          </Box>
        ) : (
          <TableContainer component={Paper} sx={{ backgroundColor: '#1C2127' }}>
            <Table stickyHeader>
              <TableHead>
                <TableRow>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Par</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Moeda Margem</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Lado</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Tamanho Delegado</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Tamanho Margem</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Alavancagem</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Lucros Realizados</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Preço Médio Abertura</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Modo Margem</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Modo Posição</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>PnL Não Realizado</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Preço Liquidação</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Taxa Manter Margem</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Preço Mark</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Preço Equilíbrio</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Taxa Total</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Taxa Deduzida</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Take Profit</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Stop Loss</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>ID Take Profit</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>ID Stop Loss</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Razão Margem</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Modo Ativo</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Data Criação</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Data Atualização/Fechamento</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>PnL Fechado</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {positions.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={26} sx={{ textAlign: 'center', color: 'white', padding: '20px' }}>
                    Nenhuma operação finalizada encontrada
                  </TableCell>
                </TableRow>
                ) : (
                  positions.map((position, index) => (
                    <TableRow key={index} sx={{ '&:hover': { backgroundColor: '#2D3748' } }}>
                      <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>{position.symbol}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.marginCoin}</TableCell>
                      <TableCell sx={{ color: 'white' }}>
                        <Chip
                          label={position.holdSide?.toUpperCase()}
                          size="small"
                          sx={{
                            backgroundColor: getSideColor(position.holdSide),
                            color: 'white',
                            fontWeight: 'bold'
                          }}
                        />
                      </TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.openDelegateSize || '0'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.marginSize, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.leverage}x</TableCell>
                      <TableCell sx={{ color: getColorByValue(parseFloat(position.achievedProfits || 0)) }}>
                        {formatCurrency(position.achievedProfits, position.marginCoin)}
                      </TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.openPriceAvg, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>
                        <Chip
                          label={getMarginModeText(position.marginMode)}
                          size="small"
                          variant="outlined"
                          sx={{ color: 'white', borderColor: 'white' }}
                        />
                      </TableCell>
                      <TableCell sx={{ color: 'white' }}>
                        <Chip
                          label={getPosModeText(position.posMode)}
                          size="small"
                          variant="outlined"
                          sx={{ color: 'white', borderColor: 'white' }}
                        />
                      </TableCell>
                      <TableCell sx={{ color: getColorByValue(parseFloat(position.unrealizedPL || 0)) }}>
                        {formatCurrency(position.unrealizedPL, position.marginCoin)}
                      </TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.liquidationPrice, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatPercentage(parseFloat(position.keepMarginRate || 0) * 100)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.markPrice, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.breakEvenPrice, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.totalFee, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.deductedFee, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>
                        {position.takeProfit ? formatCurrency(position.takeProfit, position.marginCoin) : '-'}
                      </TableCell>
                      <TableCell sx={{ color: 'white' }}>
                        {position.stopLoss ? formatCurrency(position.stopLoss, position.marginCoin) : '-'}
                      </TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.takeProfitId || '-'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.stopLossId || '-'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatPercentage(parseFloat(position.marginRatio || 0) * 100)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.assetMode || '-'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatDate(position.cTime)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatDate(position.uTime)}</TableCell>
                      <TableCell sx={{ color: getColorByValue(parseFloat(position.netProfit || 0)) }}>
                        {hideValues ? '***' : formatCurrency(parseFloat(position.netProfit || 0))}
                      </TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatDate(position.closeTime || position.uTime)}</TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </TableContainer>
        )}
      </DialogContent>
    </Dialog>
  );
};

export default FinishedOperationsModal;
